import { Badge } from "@/components/ui/badge";
import {
  Loader2, Timer, Trophy, RotateCcw, Gauge, Zap, Navigation, Play, Square, MapPin, ChevronRight, Share2, Target, History, Star
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
