const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-black/20 rounded-full animate-pulse" />
});

function polarToCartesian(centerX: number, centerY: number, radius: number, angleInDegrees: number) {
  const angleInRadians = ((angleInDegrees - 90) * Math.PI) / 180.0;
  return {
    x: centerX + radius * Math.cos(angleInRadians),
    y: centerY + radius * Math.sin(angleInRadians),
  };
}

function describeArc(x: number, y: number, radius: number, startAngle: number, endAngle: number) {
  const start = polarToCartesian(x, y, radius, endAngle);
  const end = polarToCartesian(x, y, radius, startAngle);
  const largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";
  return [
    "M", start.x, start.y,
    "A", radius, radius, 0, largeArcFlag, 0, end.x, end.y
  ].join(" ");
}

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance,
    routePoints, startTrip, startDragCountdown, stopTrip, resetTrip,
    runMode, setRunMode, dragTime, isDragFinished, isDragActive, countdown, isJumpStart,
    isNavigating, currentStep, currentRoadName, distanceToNextStep, 
    remainingDistance, remainingDuration, destination, lastRunSummary
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [activeModule, setActiveModule] = useState<'top-speed' | 'drag' | 'nav'>('top-speed');
  const [isSaving, setIsSaving] = useState(false);

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleModuleChange = (module: 'top-speed' | 'drag' | 'nav') => {
    setActiveModule(module);
    if (module === 'top-speed') setRunMode('free');
  };

  const themeColor = useMemo(() => {
    if (activeModule === 'drag') return "#eab308";
    if (activeModule === 'nav') return "#4de0f4";
    return "#ffffff";
  }, [activeModule]);

  const arrivalTime = useMemo(() => {
    if (!remainingDuration) return null;
    const now = new Date();
    return new Date(now.getTime() + remainingDuration * 1000);
  }, [remainingDuration]);

  const handleSaveToLeaderboard = async () => {
    if (!db || !user || !lastRunSummary || !profile) return;
    setIsSaving(true);
    
    try {
      const publicRunsCol = collection(db, "public_runs");
      addDocumentNonBlocking(publicRunsCol, {
        userId: user.uid,
        username: profile.username,
        profileIcon: profile.profileIcon || "speedometer",
        city: profile.city || "Kosovë",
        runType: lastRunSummary.runType,
        dragTime: lastRunSummary.time,
        peakSpeedKmH: lastRunSummary.peakSpeed,
        distanceMeters: lastRunSummary.distance,
        durationSeconds: lastRunSummary.time,
        createdAt: new Date().toISOString(),
      });
      router.push("/leaderboard");
    } finally {
      setIsSaving(false);
    }
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  const size = 360;
  const radius = 150;
  const center = size / 2;
  const rpmValue = Math.min((speed / 240) * 8, 8);
  const startAngle = 135; 
  const endAngle = 405;   
  const totalAngleRange = endAngle - startAngle;
  const currentProgressAngle = startAngle + (rpmValue / 8) * totalAngleRange;

  return (
    <div className="flex flex-col min-h-screen text-white pb-32 overflow-x-hidden safe-top relative bg-black">
      <div className="absolute inset-0 bg-gradient-to-b from-black via-zinc-950 to-red-950 pointer-events-none z-0 opacity-100" />

      <div className="flex-1 flex flex-col items-center justify-center p-6 relative z-10">
        
        <div className="flex gap-2 mb-10 bg-white/5 p-1.5 rounded-2xl border border-white/5 backdrop-blur-xl">
          <button 
            onClick={() => handleModuleChange('top-speed')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'top-speed' ? "bg-white text-black" : "text-white/40 hover:text-white"
            )}
          >
            <Gauge className="w-3.5 h-3.5" /> TOP SPEED
          </button>
          <button 
            onClick={() => handleModuleChange('drag')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'drag' ? "bg-yellow-500 text-black" : "text-white/40 hover:text-white"
            )}
          >
            <Zap className="w-3.5 h-3.5" /> DRAG
          </button>
          <button 
            onClick={() => handleModuleChange('nav')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'nav' ? "bg-[#4de0f4] text-black" : "text-white/40 hover:text-white"
            )}
          >
            <Navigation className="w-3.5 h-3.5" /> NAV
          </button>
        </div>

        {activeModule === 'drag' && (
          <div className="flex gap-3 mb-6 bg-black/40 p-1.5 rounded-2xl border border-white/5 backdrop-blur-md">
            {(['0-60', '0-100', '100-200', '1/4mile'] as RunMode[]).map((mode) => (
              <button
                key={mode}
                onClick={() => setRunMode(mode)}
                className={cn(
                  "px-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all",
                  runMode === mode ? "bg-yellow-500 text-black shadow-[0_0_15px_rgba(234,179,8,0.3)]" : "text-white/30 hover:text-white/60"
                )}
              >
                {mode === '1/4mile' ? '1/4 MILE' : mode}
              </button>
            ))}
          </div>
        )}

        {activeModule === 'drag' && countdown > 0 && (
          <div className="flex gap-4 mb-4 animate-in fade-in zoom-in duration-300">
            {[1, 2, 3, 4, 5].map((dot) => (
              <div
                key={dot}
                className={cn(
                  "w-4 h-4 rounded-full border-2 transition-all duration-300",
                  countdown >= dot 
                    ? (dot === 5 ? "bg-green-500 border-green-400 shadow-[0_0_15px_#22c55e]" : "bg-red-600 border-red-500 shadow-[0_0_15px_#dc2626]") 
                    : "bg-zinc-900 border-zinc-800"
                )}
              />
            ))}
          </div>
        )}

        <div className="relative w-[360px] h-[360px] flex items-center justify-center">
          <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
            <defs>
              <filter id="needleGlow">
                <feGaussianBlur stdDeviation="2.5" result="coloredBlur" />
                <feMerge>
                  <feMergeNode in="coloredBlur" />
                  <feMergeNode in="SourceGraphic" />
                </feMerge>
              </filter>
            </defs>

            {Array.from({ length: 81 }).map((_, i) => {
              const val = i / 10;
              const angle = startAngle + (val / 8) * totalAngleRange;
              const isMajor = i % 10 === 0;
              const isRedline = val >= 6;
              const angleRad = (angle - 90) * Math.PI / 180;
              const x1 = center + (radius - (isMajor ? 15 : 8)) * Math.cos(angleRad);
              const y1 = center + (radius - (isMajor ? 15 : 8)) * Math.sin(angleRad);
              const x2 = center + radius * Math.cos(angleRad);
              const y2 = center + radius * Math.sin(angleRad);
              return (
                <g key={i}>
                  <line
                    x1={x1} y1={y1} x2={x2} y2={y2}
                    stroke={isRedline ? "#ef4444" : themeColor}
                    strokeWidth={isMajor ? 2 : 1}
                    opacity={isMajor ? 0.6 : 0.2}
                  />
                  {isMajor && (
                    <text
                      x={center + (radius - 35) * Math.cos(angleRad)}
                      y={center + (radius - 35) * Math.sin(angleRad)}
                      fill={isRedline ? "#ef4444" : themeColor}
                      fontSize="14"
                      fontWeight="300"
                      textAnchor="middle"
                      alignmentBaseline="middle"
                      className="opacity-60"
                    >
                      {val}
                    </text>
                  )}
                </g>
              );
            })}

            {activeModule !== 'nav' && (
              <path
                d={describeArc(center, center, radius - 3, startAngle, currentProgressAngle)}
                fill="none"
                stroke={themeColor}
                strokeWidth="4"
                strokeLinecap="round"
                opacity="0.8"
                style={{ filter: 'url(#needleGlow)', transition: 'all 0.1s ease-out' }}
              />
            )}

            {activeModule !== 'nav' && (
              <line
                x1={center + (radius - 120) * Math.cos((currentProgressAngle - 90) * Math.PI / 180)}
                y1={center + (radius - 120) * Math.sin((currentProgressAngle - 90) * Math.PI / 180)}
                x2={center + (radius - 5) * Math.cos((currentProgressAngle - 90) * Math.PI / 180)}
                y2={center + (radius - 5) * Math.cos((currentProgressAngle - 90) * Math.PI / 180)}
                stroke="#ef4444"
                strokeWidth="4"
                strokeLinecap="round"
                style={{ filter: 'url(#needleGlow)', transition: 'all 0.1s ease-out' }}
              />
            )}
            
            <text x={center + 100} y={center + 100} fill={themeColor} fontSize="24" fontWeight="300" className="opacity-40">
              {speed > 0 ? "D" : "P"}
            </text>

            <text x={center} y={center + 140} fill={themeColor} fontSize="9" textAnchor="middle" className="opacity-20 font-bold tracking-widest uppercase">
              /min x1000
            </text>
          </svg>

          <div className="absolute inset-0 flex flex-col items-center justify-center overflow-hidden">
             {activeModule === 'nav' ? (
                <div className="w-[280px] h-[280px] rounded-full overflow-hidden border border-white/10 relative">
                   <RouteMap points={routePoints} />
                   <div className="absolute bottom-6 right-6 bg-black/80 backdrop-blur-md px-3 py-1 rounded-xl border border-white/10 flex flex-col items-center">
                      <span className="text-2xl font-black leading-none">{speed}</span>
                      <span className="text-[6px] font-bold text-white/40 uppercase">KM/H</span>
                   </div>
                </div>
             ) : (
                <div className="relative">
                  <div className="flex flex-col items-center">
                    <span className={cn(
                      "text-8xl font-black tracking-tighter tabular-nums leading-none transition-all duration-300",
                      activeModule === 'drag' ? "text-yellow-500" : "text-white"
                    )}>
                      {speed}
                    </span>
                    <span className="text-sm font-light text-white/40 uppercase tracking-widest mt-2">km/h</span>
                  </div>

                  {activeModule === 'drag' && dragTime !== null && dragTime > 0 && (
                    <div className="absolute -bottom-16 left-1/2 -translate-x-1/2 w-max text-center animate-in fade-in slide-in-from-bottom-4">
                      <p className="text-[10px] font-black text-yellow-500/60 uppercase tracking-widest">{runMode} TIME</p>
                      <p className="text-3xl font-black italic text-yellow-500">{dragTime.toFixed(2)}s</p>
                    </div>
                  )}
                </div>
             )}
          </div>
        </div>

        {activeModule === 'drag' && !isDragFinished && !isJumpStart && (
          <div className="grid grid-cols-2 gap-4 w-full max-w-[340px] mt-8 animate-in fade-in slide-in-from-bottom-4">
             <Card className="glass border-yellow-500/20 p-4 rounded-2xl flex flex-col items-center">
                <span className="text-[8px] font-black text-white/30 uppercase tracking-widest">MISSION</span>
                <span className="text-lg font-black italic text-yellow-500 uppercase">{runMode}</span>
             </Card>
             <Card className="glass border-yellow-500/20 p-4 rounded-2xl flex flex-col items-center">
                <span className="text-[8px] font-black text-white/30 uppercase tracking-widest">STATUS</span>
                <span className={cn("text-lg font-black italic uppercase", isDragActive ? "text-green-500 animate-pulse" : "text-white/40")}>
                  {isDragActive ? "RACING" : countdown > 0 ? "READY" : "WAITING"}
                </span>
             </Card>
          </div>
        )}

        {isJumpStart && (
          <Card className="w-full max-w-[340px] mt-8 bg-red-600/20 border-red-500/40 p-6 rounded-3xl text-center animate-bounce">
             <span className="text-xl font-black italic text-red-500 uppercase">JUMP START!</span>
             <p className="text-[10px] font-black text-white/60 uppercase tracking-widest mt-2">Nisja e parakohshme. Provo përsëri.</p>
          </Card>
        )}

        {lastRunSummary && !isDriving && (
          <div className="w-full max-w-[360px] mt-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <Carousel className="w-full">
              <CarouselContent>
                <CarouselItem>
                  <Card className="glass border-white/10 p-6 rounded-[2.5rem] bg-white/5 backdrop-blur-2xl relative overflow-hidden">
                    <div className="flex justify-between items-start mb-6">
                      <div>
                        <Badge className="bg-accent/10 border-accent/20 text-accent text-[8px] font-black uppercase tracking-widest mb-1">RUN COMPLETED</Badge>
                        <h3 className="text-xl font-black italic text-white uppercase">{lastRunSummary.runType} MISSION</h3>
                      </div>
                      <div className="text-right">
                        <span className="text-4xl font-black italic text-accent">{lastRunSummary.time.toFixed(2)}s</span>
                      </div>
                    </div>

                    <div className="h-40 w-full rounded-2xl overflow-hidden border border-white/5 mb-6 relative">
                       <RouteMap points={lastRunSummary.points} />
                    </div>

                    <div className="grid grid-cols-3 gap-4">
                      <div className="flex flex-col">
                        <span className="text-[7px] font-black text-white/30 uppercase tracking-widest">PEAK SPEED</span>
                        <span className="text-sm font-black italic text-white">{lastRunSummary.peakSpeed} km/h</span>
                      </div>
                      <div className="flex flex-col">
                        <span className="text-[7px] font-black text-white/30 uppercase tracking-widest">AVG SPEED</span>
                        <span className="text-sm font-black italic text-white">{lastRunSummary.avgSpeed} km/h</span>
                      </div>
                      <div className="flex flex-col">
                        <span className="text-[7px] font-black text-white/30 uppercase tracking-widest">DISTANCE</span>
                        <span className="text-sm font-black italic text-white">{lastRunSummary.distance}m</span>
                      </div>
                    </div>
                  </Card>
                </CarouselItem>

                <CarouselItem>
                  <Card className="glass border-accent/30 p-8 rounded-[2.5rem] bg-accent/5 backdrop-blur-2xl h-full flex flex-col items-center justify-center text-center">
                    <div className="w-20 h-20 bg-accent/20 rounded-3xl flex items-center justify-center mb-6 shadow-[0_0_30px_rgba(77,224,244,0.3)]">
                       <Trophy className="w-10 h-10 text-accent" />
                    </div>
                    <h3 className="text-2xl font-black italic text-white uppercase tracking-tighter">PERFORMANCË E ELITËS</h3>
                    <div className="space-y-4 mt-6">
                       <div className="flex items-center gap-3 bg-white/5 px-6 py-3 rounded-2xl border border-white/5">
                          <Star className="w-5 h-5 text-accent fill-accent" />
                          <span className="text-sm font-black uppercase tracking-widest">NR. 1 NË PRIZREN SOT</span>
                       </div>
                       <div className="flex items-center gap-3 bg-white/5 px-6 py-3 rounded-2xl border border-white/5">
                          <Trophy className="w-5 h-5 text-white/40" />
                          <span className="text-sm font-black uppercase tracking-widest">NR. 4 NË KOSOVË SOT</span>
                       </div>
                    </div>
                    <Button 
                      onClick={handleSaveToLeaderboard}
                      disabled={isSaving}
                      className="w-full mt-8 h-14 bg-accent text-background font-black uppercase rounded-2xl shadow-xl active:scale-95 transition-all"
                    >
                      {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : "PUBLIKO NË RANKING"}
                    </Button>
                  </Card>
                </CarouselItem>
              </CarouselContent>
            </Carousel>
          </div>
        )}

        <div className="w-full max-w-[340px] mt-8">
           <Button
             onClick={
               isDriving 
                ? stopTrip 
                : (activeModule === 'drag' ? startDragCountdown : startTrip)
             }
             className={cn(
               "w-full h-16 rounded-3xl font-black text-sm uppercase tracking-widest transition-all shadow-lg",
               isDriving 
                ? "bg-red-600 text-white hover:bg-red-700 shadow-red-600/20" 
                : "bg-accent text-background hover:bg-accent/90 shadow-accent/20"
             )}
           >
             {isDriving ? (
               <div className="flex items-center gap-3">
                 <Square className="w-5 h-5 fill-current" />
                 Stop Trip
               </div>
             ) : (
               <div className="flex items-center gap-3">
                 <Zap className="w-5 h-5 fill-current" />
                 {activeModule === 'drag' ? "Record Run" : "Start Trip"}
               </div>
             )}
           </Button>
           
           {!isDriving && (peakSpeed > 0 || lastRunSummary) && (
             <Button 
               variant="ghost" 
               onClick={resetTrip}
               className="w-full mt-4 h-10 rounded-2xl font-black text-[10px] uppercase tracking-widest text-zinc-600 hover:text-white"
             >
               <RotateCcw className="w-3 mr-2" /> RESET TELEMETRY
             </Button>
           )}
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
